const payload = (() => {
  try {
    return JSON.parse(String(items[0]?.json?.stdout ?? '{}'));
  } catch (error) {
    return {
      checked_at: null,
      containers: [],
      meta_error: `invalid_json:${error.message}`,
    };
  }
})();

const env = typeof process !== 'undefined' && process?.env ? process.env : {};
const cooldownHoursRaw = Number(env.CONTAINER_ALERT_COOLDOWN_HOURS ?? 5);
const cooldownHours = Number.isFinite(cooldownHoursRaw) && cooldownHoursRaw > 0 ? cooldownHoursRaw : 5;
const cooldownMs = cooldownHours * 60 * 60 * 1000;
const pingTimeoutRaw = Number(env.CONTAINER_PING_TIMEOUT_MS ?? 10000);
const pingTimeoutMs = Number.isFinite(pingTimeoutRaw) && pingTimeoutRaw > 0 ? pingTimeoutRaw : 10000;
const now = Date.now();
const store = typeof $getWorkflowStaticData === 'function' ? $getWorkflowStaticData('global') : null;
const state = store?.containerAlertState && typeof store.containerAlertState === 'object'
  ? store.containerAlertState
  : {};
const nextState = {};
const dueAlerts = [];

const parsePingTargets = () => {
  const raw = String(env.CONTAINER_PING_TARGETS ?? '').trim();
  if (!raw) {
    return { targets: {}, error: null };
  }

  try {
    const parsed = JSON.parse(raw);
    if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) {
      return { targets: {}, error: 'CONTAINER_PING_TARGETS deve ser um objeto JSON' };
    }

    const entries = Object.entries(parsed)
      .filter(([key, value]) => String(key).trim() && typeof value === 'string' && value.trim())
      .reduce((acc, [key, value]) => {
        acc[String(key).trim()] = value.trim();
        return acc;
      }, {});

    return { targets: entries, error: null };
  } catch (error) {
    return { targets: {}, error: `CONTAINER_PING_TARGETS invalido: ${error.message}` };
  }
};

const pingConfig = parsePingTargets();

const buildKey = (container) => {
  if (container.compose_project && container.compose_service) {
    return `${container.compose_project}/${container.compose_service}`;
  }
  return String(container.name || container.id || 'unknown');
};

const buildDisplay = (container) => {
  if (container.compose_project && container.compose_service) {
    return `${container.compose_project}/${container.compose_service} (${container.name})`;
  }
  return String(container.name || container.id || 'container sem nome');
};

const resolvePingTarget = (container) => {
  const keys = [];
  if (container.compose_project && container.compose_service) {
    keys.push(`${container.compose_project}/${container.compose_service}`);
  }
  if (container.compose_service) {
    keys.push(String(container.compose_service));
  }
  if (container.name) {
    keys.push(String(container.name));
  }

  for (const key of keys) {
    if (pingConfig.targets[key]) {
      return pingConfig.targets[key];
    }
  }

  return '';
};

const getInactiveReason = (container) => {
  const status = String(container.status ?? 'unknown').toLowerCase();
  const health = container.health == null ? '' : String(container.health).toLowerCase();
  const exitCode = container.exit_code;
  const error = String(container.error ?? '').trim();

  if (!container.running) {
    const details = [`status=${status || 'unknown'}`];
    if (exitCode !== null && exitCode !== undefined && status !== 'running') {
      details.push(`exitCode=${exitCode}`);
    }
    if (error) {
      details.push(`erro=${error}`);
    }
    return details.join(' | ');
  }

  if (health === 'unhealthy') {
    return 'health=unhealthy';
  }

  if (['dead', 'exited', 'paused', 'restarting', 'removing'].includes(status)) {
    return `status=${status}`;
  }

  return '';
};

const runPingCheck = async (url) => {
  const controller = typeof AbortController !== 'undefined' ? new AbortController() : null;
  const timeout = controller ? setTimeout(() => controller.abort(), pingTimeoutMs) : null;
  const startedAt = Date.now();

  try {
    const response = await fetch(url, {
      method: 'GET',
      redirect: 'follow',
      signal: controller?.signal,
      headers: {
        Accept: 'application/json,text/plain,*/*',
        'User-Agent': 'n8n-container-health-alerts/1.0',
      },
    });
    const latencyMs = Date.now() - startedAt;
    return {
      ok: response.status === 200,
      status: response.status,
      latencyMs,
      error: response.status === 200 ? null : `ping_http_status=${response.status}`,
    };
  } catch (error) {
    const latencyMs = Date.now() - startedAt;
    const message = error?.name === 'AbortError'
      ? `ping_timeout>${pingTimeoutMs}ms`
      : `ping_erro=${error?.message || String(error)}`;
    return {
      ok: false,
      status: null,
      latencyMs,
      error: message,
    };
  } finally {
    if (timeout) {
      clearTimeout(timeout);
    }
  }
};

const registerAlert = (key, display, reason, extra = {}) => {
  const previous = state[key] && typeof state[key] === 'object' ? state[key] : null;
  const lastSentAt = Number(previous?.lastSentAt ?? 0);
  const shouldAlert = !lastSentAt || now - lastSentAt >= cooldownMs;

  nextState[key] = {
    display,
    reason,
    lastSentAt: shouldAlert ? now : lastSentAt,
  };

  if (shouldAlert) {
    dueAlerts.push({
      display,
      reason,
      image: '',
      started_at: null,
      finished_at: null,
      ping_url: '',
      ping_http_status: null,
      ping_latency_ms: null,
      ...extra,
    });
  }
};

for (const container of Array.isArray(payload.containers) ? payload.containers : []) {
  const key = buildKey(container);
  const display = buildDisplay(container);
  const inactiveReason = getInactiveReason(container);

  if (inactiveReason) {
    registerAlert(key, display, inactiveReason, {
      image: String(container.image ?? ''),
      started_at: container.started_at,
      finished_at: container.finished_at,
    });
    continue;
  }

  const pingUrl = resolvePingTarget(container);
  if (!pingUrl) {
    continue;
  }

  const pingResult = await runPingCheck(pingUrl);
  if (pingResult.ok) {
    continue;
  }

  const reasonParts = [pingResult.error || 'ping_http_status_desconhecido'];
  if (pingResult.latencyMs !== null && pingResult.latencyMs !== undefined) {
    reasonParts.push(`ping_latency_ms=${pingResult.latencyMs}`);
  }

  registerAlert(`${key}::ping`, display, reasonParts.join(' | '), {
    image: String(container.image ?? ''),
    started_at: container.started_at,
    finished_at: container.finished_at,
    ping_url: pingUrl,
    ping_http_status: pingResult.status,
    ping_latency_ms: pingResult.latencyMs,
  });
}

if (payload.meta_error) {
  registerAlert('__collector__', 'coleta_docker', String(payload.meta_error));
}

if (pingConfig.error) {
  registerAlert('__ping_config__', 'configuracao_ping', pingConfig.error);
}

if (store) {
  store.containerAlertState = nextState;
}

if (dueAlerts.length === 0) {
  return [];
}

const lines = [
  'Alerta de containers',
  '',
  `Checado em: ${payload.checked_at ?? 'n/d'}`,
  `Cooldown atual: ${cooldownHours} hora(s)`,
  `Timeout de ping: ${pingTimeoutMs} ms`,
  '',
  'Containers com problema:',
  ...dueAlerts.map((alert) => {
    const details = [
      `- ${alert.display}`,
      `  motivo: ${alert.reason}`,
    ];
    if (alert.ping_url) {
      details.push(`  ping_url: ${alert.ping_url}`);
    }
    if (alert.ping_http_status !== null && alert.ping_http_status !== undefined) {
      details.push(`  ping_http_status: ${alert.ping_http_status}`);
    }
    if (alert.ping_latency_ms !== null && alert.ping_latency_ms !== undefined) {
      details.push(`  ping_latency_ms: ${alert.ping_latency_ms}`);
    }
    if (alert.image) {
      details.push(`  image: ${alert.image}`);
    }
    if (alert.started_at) {
      details.push(`  started_at: ${alert.started_at}`);
    }
    if (alert.finished_at && alert.finished_at !== '0001-01-01T00:00:00Z') {
      details.push(`  finished_at: ${alert.finished_at}`);
    }
    return details.join('\n');
  }),
].join('\n');

return [{
  json: {
    hasAlerts: true,
    cooldownHours,
    checked_at: payload.checked_at,
    inactiveCount: dueAlerts.length,
    alerts: dueAlerts,
    message: lines,
  },
}];
